VALUES
  ('social-worker-moex-07940', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「分析與選擇的過程，它係針對未來所要完成的工作，配合其對未來環境的評估分析來設定工作目標， 並擬訂與擇定用來達成目標的可能方案」，這段敘述是指：', '["組織", "分工", "領導", "規劃"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07941', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「如果不向福利機構提出申請的話就無法使用服務」，這段文字在說明什麼需求？', '["規範需求", "感覺需求", "表達需求", "比較需求"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07942', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「將實際提供服務的狀況與該項服務需求的狀況做比較，以瞭解服務方案究竟產生何種影響或效應 （impact）」，這種評估稱為：', '["適切性評估", "總結性評估", "結果性評估", "效率性評估"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07943', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '將例行性的表格檢查交由一位社工負責，可能使這位社工厭倦而離職，因此在工作設計上做有計畫地交 換工作，以增加員工間的瞭解與合作，此種方式稱為：', '["工作輪調", "工作擴大化", "工作豐富化", "工作效率化"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07944', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某社會福利機構的創辦人以服務弱勢家庭兒童為職志，員工因受其精神感召，而願意追隨。此種機構領 導者所擁有的權力來源稱為：', '["法定權力", "專家權力", "訊息權力", "參考權力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07945', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某一個企業組織員工自殺案件頻傳，負責人決定引進員工協助方案（employee assistance program, EAP）， 於是與一個社會工作師事務所訂定合約提供諮商服務，這種模式稱為：', '["公司內模式", "合夥模式", "會員模式", "公司外模式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07946', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在管理的決策過程中，運用一個專家團體給與問卷作答，然後依據結果做初步彙整，再依據彙整結果修 正問卷，如此重複幾次後得到共識，以做為決策的依據，這種決策方式稱為：', '["決策樹狀圖分析（decision-tree analysis）", "德爾菲法（Delphi method）", "腦力激盪（brainstorming）", "名義團體技術（nominal group technique）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07947', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「申請者為有效完成工作需具備之知識、技術與能力」，這個定義是指？', '["工作分析", "工作聲明", "工作說明", "工作規範"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07948', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關志工訓練方面，下列敘述何者正確？', '["依據志願服務法相關規定，志工的基礎訓練與特殊訓練時數均為16小時", "依據志願服務法相關規定，受完基礎訓練之後，運用單位即應給與志願服務紀錄冊", "為讓新進員工確實瞭解處理工作任務、技術、程序與方法，運用單位可以辦理專業技術性職前訓練", "為工作績效優異極具有發展潛能的志工，運用單位可以給予補充學識技能訓練"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07949', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '隨著社會環境的變遷，社會福利機構必然遭受各項考驗和挑戰，面對這種變動，社會工作管理者要如何 面對如此變革，下列何者不正確？', '["強調變革過程中「組織」的面向", "讓所有相關者參與計畫並將問題告知使其能找出解決方法", "要找出變革中的重要人物和關聯性", "將管理變革的過程視為和相關員工的共事過程"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
